     116: 				len = 2;
     117: 			} else if (ptr[1] == '{') {
     118: 				if (!light_isdigit(ptr[2]))
     119: 					return mod_evhost_parse_pattern_err(bptr);
     120: 				if (ptr[3] == '.') {
     121: 					if (!light_isdigit(ptr[4]))
