     126: 				} else if (ptr[3] == '}') {
     127: 					len = 4;
     128: 				} else {
     129: 					return mod_evhost_parse_pattern_err(bptr);
     130: 				}
     131: 			} else {
     132: 				return mod_evhost_parse_pattern_err(bptr);
     133: 			}
     134: 
     135: 			buffer_copy_string_len(bptr+used, pos, ptr-pos);
     136: 			pos = ptr + len;
     137: 
     138: 			buffer_copy_string_len(bptr+used+1, ptr, len);
     139: 			ptr += len - 1; /*(ptr++ in for() loop)*/
     140: 
     141: 			used += 2;
     142: 		}
     143: 	}
     144: 
     145: 	if(*pos != '\0') {
     146: 		if (used >= sz) /* (should not happen) */
     147: 			return mod_evhost_parse_pattern_err(bptr);
