     660: static fam_dir_entry * fam_dir_monitor(stat_cache_fam *scf, char *fn, uint32_t dirlen, struct stat *st)
     661: {
     662:     if (NULL == scf->fdn) return NULL; /* FAM connection closed; do nothing */
     663:     const int fn_is_dir = S_ISDIR(st->st_mode);
     664:     /*force_assert(0 != dirlen);*/
     665:     /*force_assert(fn[0] == '/');*/
     666:     /* consistency: ensure fn does not end in '/' unless root "/"
     667:      * FAM events will not end in '/', so easier to match this way */
     668:     if (fn[dirlen-1] == '/') --dirlen;
     669:     if (0 == dirlen) dirlen = 1; /* root dir ("/") */
     670:     /* Note: paths are expected to be normalized before calling stat_cache,
     671:      * e.g. without repeated '/' */
     672:     if (!fn_is_dir) {
     673:         while (fn[--dirlen] != '/') ;
     674:         if (0 == dirlen) dirlen = 1; /*(file in root dir)*/
     675:     }
     676:     int dir_ndx;
     677:     fam_dir_entry *fam_dir =
     678:       stat_cache_sptree_ndx(&scf->dirs, &dir_ndx, fn, dirlen);
     679: 
     680:     if (NULL != fam_dir) {
     681:         if (!buffer_eq_slen(&fam_dir->name, fn, dirlen)) {
     682:             /* hash collision; preserve existing
     683:              * do not monitor new to avoid cache thrashing */
     684:             return NULL;
     685:         }
     686:         /* directory already registered */
     687:     }
     688: 
     689:     const unix_time64_t cur_ts = log_monotonic_secs;
     690:     struct stat lst;
     691:     int ck_dir = fn_is_dir;
     692:     if (!fn_is_dir && (NULL==fam_dir || cur_ts - fam_dir->stat_ts >= 16)) {
     693:         ck_dir = 1;
     694:       if (dirlen > 1) {
     695:         /*(temporarily modify fn)*/
     696:         fn[dirlen] = '\0';
     697:         if (0 != lstat(fn, &lst)) {
     698:             fn[dirlen] = '/';
     699:             return NULL;
     700:         }
     701:         if (!S_ISLNK(lst.st_mode)) {
     702:             st = &lst;
     703:         }
     704:         else if (0 != stat(fn, st)) { /*st passed in now is stat() of dir*/
     705:             fn[dirlen] = '/';
     706:             return NULL;
     707:         }
     708:         fn[dirlen] = '/';
     709:       }
     710:       else if (0 != stat("/", (st = &lst))) /*assume "/" is dir, not symlink*/
     711:         return NULL;
     712:     }
     713: 
     714:     int ck_lnk = (NULL == fam_dir);
     715:     if (ck_dir && NULL != fam_dir) {
     716:         /* check stat() matches device and inode, just in case an external event
     717:          * not being monitored occurs (e.g. rename of unmonitored parent dir)*/
     718:         if (st->st_dev != fam_dir->st_dev || st->st_ino != fam_dir->st_ino) {
     719:             ck_lnk = 1;
     720:             /*(modifies scf->dirs but no need to re-splay for dir_ndx since
     721:              * fam_dir is not NULL and so splaytree_insert not called below)*/
     722:             if (scf->dirs) fam_dir_invalidate_tree(scf->dirs, fn, dirlen);
