     771:         fam_dir->st_ino = st->st_ino;
     772:     }
     773: 
     774:     if (ck_lnk) {
     775:         if (fn_is_dir) {
     776:             /*(temporarily modify fn)*/
     777:             char e = fn[dirlen];
     778:             fn[dirlen] = '\0';
     779:             if (0 != lstat(fn, &lst)) {
