     216: static format_fields * accesslog_parse_format(const char * const format, const uint32_t flen, log_error_st * const errh) {
     217:     /* common log format (the default) results in 18 elements,
     218:      * so 127 should be enough except for obscene custom usage */
     219:     uint32_t used = 0;
     220:     const uint32_t sz = 127;/* (sz+1 must match fptr[] num elts below) */
     221:     format_field *f;
     222:     format_field fptr[128]; /* (128 elements takes 4k on stack in 64-bit) */
     223:     memset(fptr, 0, sizeof(fptr));
     224:     /*assert(FORMAT_UNSET == 0);*/
     225:     if (0 == flen) return NULL;
     226:     uint32_t i = 0;
     227:     do {
     228:         uint32_t start = i;
     229:         while (format[i] != '%' && ++i < flen) ;
     230:         if (start != i) {
     231:             /* save string from start to i */
     232:             if (used && (f = fptr+used-1)->field == FORMAT_LITERAL)
     233:                 buffer_append_string_len(&f->string, format + start, i - start);
     234:             else {
     235:                 if (used == sz)
     236:                     return accesslog_parse_format_err(errh, __FILE__, __LINE__, fptr,
     237:                              "too many fields (>= 127) in accesslog.format");
     238: 
     239:                 f = fptr + used++;
     240:                 f->field = FORMAT_LITERAL;
     241:                 buffer_copy_string_len(&f->string, format + start, i - start);
     242:             }
     243:         }
     244:         if (i == flen) break;
     245: 
     246:         uint32_t k = ++i; /* step over '%' */
     247:         if (i == flen)
     248:             return accesslog_parse_format_err(errh, __FILE__, __LINE__, fptr,
     249:               "% must be followed by a format-specifier");
     250: 
     251:         /* we need a new field */
     252:         if (used == sz)
     253:             return accesslog_parse_format_err(errh, __FILE__, __LINE__, fptr,
     254:               "too many fields (>= 127) in accesslog.format");
     255: 
     256:         /* search for the terminating command */
     257:         if (format[i] == '{') {
     258:             k = ++i;
     259:             while (i < flen && format[i] != '}') ++i;
     260:             if (i == flen || i == k) {
     261:                 return accesslog_parse_format_err(errh,__FILE__,__LINE__,fptr,
     262:                   "%{...} must contain string and %{ must be terminated by }");
     263:             }
     264:             ++i;
     265:         }
     266:         else {
     267:             /* skip over (ignore) '<' or '>' */
     268:             if (format[i] == '<' || format[i] == '>') k = ++i;
     269: 
     270:             /* special-case "%%" and "%l" */
     271:             if (i < flen && (format[i] == '%' || format[i] == 'l')) {
     272:                 /* replace "%%" with literal '%' */
     273:                 /* replace "%l" with literal '-'; ignore remote ident */
     274:                 if (0 == used || (f = fptr+used-1)->field != FORMAT_LITERAL) {
     275:                     f = fptr + used++;
     276:                     f->field = FORMAT_LITERAL;
     277:                 }
     278:                 buffer_append_char(&f->string, format[i] == '%' ? '%' : '-');
     279:                 continue;
     280:             }
     281:         }
     282:         /* add field */
     283:         f = fptr + used++;
     284:         if (i != k) /* %{...} */
     285:             buffer_copy_string_len(&f->string, format + k, i - k - 1);
     286:         f->field = (i < flen)
     287:           ? accesslog_parse_format_token(format[i])
     288:           : FORMAT_UNSET;
     289: 
     290:         if (f->field == FORMAT_UNSET)
     291:             return accesslog_parse_format_err(errh, __FILE__, __LINE__, fptr,
     292:               "% or %{...} must be followed by a valid format-specifier");
     293:     } while (++i < flen);
     294: 
     295:     format_fields * const fields =
>>   296:       ck_malloc(sizeof(format_fields) + ((used+1) * sizeof(format_field)));
     297:     memset(fields, 0, sizeof(format_fields));
     298:     memcpy(fields->ptr, fptr, (used+1) * sizeof(format_field));
     299:     return fields;
     300: }

