     698:             fn[dirlen] = '/';
     699:             return NULL;
     700:         }
     701:         if (!S_ISLNK(lst.st_mode)) {
     702:             st = &lst;
     703:         }
     704:         else if (0 != stat(fn, st)) { /*st passed in now is stat() of dir*/
     705:             fn[dirlen] = '/';
     706:             return NULL;
     707:         }
     708:         fn[dirlen] = '/';
     709:       }
