    1108: void stat_cache_update_entry(const char *name, uint32_t len,
    1109:                              const struct stat *st, const buffer *etagb)
    1110: {
    1111:     if (sc.stat_cache_engine == STAT_CACHE_ENGINE_NONE) return;
    1112:     if (__builtin_expect( (0 == len), 0)) return; /*(should not happen)*/
    1113:     if (name[len-1] == '/') { if (0 == --len) len = 1; }
    1114:     splay_tree **sptree = &sc.files;
    1115:     stat_cache_entry *sce =
    1116:       stat_cache_sptree_find(sptree, name, len);
    1117:     if (sce && buffer_is_equal_string(&sce->name, name, len)) {
    1118:         if (!stat_cache_stat_eq(&sce->st, st)) {
    1119:             /* etagb might be NULL to clear etag (invalidate) */
    1120:             buffer_clear(&sce->etag);
    1121:             if (etagb)
    1122:                 buffer_copy_string_len(&sce->etag, BUF_PTR_LEN(etagb));
    1123:           #if defined(HAVE_XATTR) || defined(HAVE_EXTATTR)
    1124:             buffer_clear(&sce->content_type);
    1125:           #endif
    1126:             if (sce->fd >= 0) {
    1127:                 if (1 == sce->refcnt) {
    1128:                     close(sce->fd);
    1129:                     sce->fd = -1;
    1130:                 }
    1131:                 else {
    1132:                     --sce->refcnt; /* stat_cache_entry_free(sce); */
>>  1133:                     (*sptree)->data = sce = stat_cache_entry_init();
    1134:                     buffer_copy_string_len(&sce->name, name, len);
    1135:                 }
    1136:             }
    1137:             sce->st = *st;
    1138:         }
    1139:         sce->stat_ts = log_monotonic_secs;
    1140:     }
    1141: }

