     351: __attribute_noinline__
     352: __attribute_returns_nonnull__
     353: static buffer * chunk_buffer_acquire_sz(const size_t sz) {
     354:     chunk *c;
     355:     buffer *b;
     356:     if (sz <= (chunk_buf_sz|1)) {
     357:         if (chunks) {
     358:             c = chunks;
     359:             chunks = c->next;
     360:         }
     361:         else
>>   362:             c = chunk_init_sz(chunk_buf_sz);
     363:     }
     364:     else {
     365:         c = chunk_pop_oversized(sz);
     366:         if (NULL == c) {
     367:             /*(round up to nearest chunk_buf_sz)*/
     368:             /* NB: round down power-2 + 1 to avoid excess allocation
     369:              * (sz & ~1uL) relies on buffer_realloc() adding +1 *and* on callers
     370:              * of this func never passing power-2 + 1 sz unless direct caller
     371:              * adds +1 for '\0', as is done in chunk_buffer_prepare_append() */
     372:             c = chunk_init_sz(((sz&~1uL)+(chunk_buf_sz-1)) & ~(chunk_buf_sz-1));
     373:         }
     374:     }
     375:     c->next = chunk_buffers;
     376:     chunk_buffers = c;
     377:     b = c->mem;
     378:     c->mem = NULL;
     379:     return b;
     380: }

     386: void chunk_buffer_release(buffer *b) {
>>   387:     if (NULL == b) return;
     388:     if (chunk_buffers) {
     389:         chunk *c = chunk_buffers;
     390:         chunk_buffers = c->next;
     391:         c->mem = b;
     392:         buffer_clear(b);
>>   393:         if (b->size == (chunk_buf_sz|1)) {
     394:             c->next = chunks;
     395:             chunks = c;
     396:         }
>>   397:         else if (b->size > chunk_buf_sz)
     398:             chunk_push_oversized(c, b->size);
     399:         else
     400:             chunk_free(c);
     401:     }
     402:     else {
     403:         buffer_free(b);
     404:     }
     405: }

     660: static fam_dir_entry * fam_dir_monitor(stat_cache_fam *scf, char *fn, uint32_t dirlen, struct stat *st)
     661: {
     662:     if (NULL == scf->fdn) return NULL; /* FAM connection closed; do nothing */
     663:     const int fn_is_dir = S_ISDIR(st->st_mode);
     664:     /*force_assert(0 != dirlen);*/
     665:     /*force_assert(fn[0] == '/');*/
     666:     /* consistency: ensure fn does not end in '/' unless root "/"
     667:      * FAM events will not end in '/', so easier to match this way */
     668:     if (fn[dirlen-1] == '/') --dirlen;
     669:     if (0 == dirlen) dirlen = 1; /* root dir ("/") */
     670:     /* Note: paths are expected to be normalized before calling stat_cache,
     671:      * e.g. without repeated '/' */
     672:     if (!fn_is_dir) {
     673:         while (fn[--dirlen] != '/') ;
     674:         if (0 == dirlen) dirlen = 1; /*(file in root dir)*/
     675:     }
     676:     int dir_ndx;
     677:     fam_dir_entry *fam_dir =
     678:       stat_cache_sptree_ndx(&scf->dirs, &dir_ndx, fn, dirlen);
     679: 
     680:     if (NULL != fam_dir) {
     681:         if (!buffer_eq_slen(&fam_dir->name, fn, dirlen)) {
     682:             /* hash collision; preserve existing
     683:              * do not monitor new to avoid cache thrashing */
     684:             return NULL;
     685:         }
     686:         /* directory already registered */
     687:     }
     688: 
     689:     const unix_time64_t cur_ts = log_monotonic_secs;
     690:     struct stat lst;
     691:     int ck_dir = fn_is_dir;
     692:     if (!fn_is_dir && (NULL==fam_dir || cur_ts - fam_dir->stat_ts >= 16)) {
     693:         ck_dir = 1;
     694:       if (dirlen > 1) {
     695:         /*(temporarily modify fn)*/
     696:         fn[dirlen] = '\0';
     697:         if (0 != lstat(fn, &lst)) {
     698:             fn[dirlen] = '/';
     699:             return NULL;
     700:         }
     701:         if (!S_ISLNK(lst.st_mode)) {
     702:             st = &lst;
     703:         }
     704:         else if (0 != stat(fn, st)) { /*st passed in now is stat() of dir*/
     705:             fn[dirlen] = '/';
     706:             return NULL;
     707:         }
     708:         fn[dirlen] = '/';
     709:       }
     710:       else if (0 != stat("/", (st = &lst))) /*assume "/" is dir, not symlink*/
     711:         return NULL;
     712:     }
     713: 
     714:     int ck_lnk = (NULL == fam_dir);
     715:     if (ck_dir && NULL != fam_dir) {
     716:         /* check stat() matches device and inode, just in case an external event
     717:          * not being monitored occurs (e.g. rename of unmonitored parent dir)*/
     718:         if (st->st_dev != fam_dir->st_dev || st->st_ino != fam_dir->st_ino) {
     719:             ck_lnk = 1;
     720:             /*(modifies scf->dirs but no need to re-splay for dir_ndx since
     721:              * fam_dir is not NULL and so splaytree_insert not called below)*/
     722:             if (scf->dirs) fam_dir_invalidate_tree(scf->dirs, fn, dirlen);
     723:             if (!fn_is_dir) /*(if dir, caller is updating stat_cache_entry)*/
     724:                 stat_cache_update_entry(fn, dirlen, st, NULL);
     725:             /*(must not delete tree since caller is holding a valid node)*/
     726:             stat_cache_invalidate_dir_tree(fn, dirlen);
     727:           #ifdef HAVE_SYS_INOTIFY_H
     728:             scf->wds = splaytree_delete(scf->wds, fam_dir->req);
     729:           #endif
     730:             if (0 != FAMCancelMonitor(&scf->fam, &fam_dir->req)
     731:                 || 0 != FAMMonitorDirectory(&scf->fam, fam_dir->name.ptr,
     732:                                             &fam_dir->req,
     733:                                             (void *)(intptr_t)dir_ndx)) {
     734:                 fam_dir->stat_ts = 0; /* invalidate */
     735:                 return NULL;
     736:             }
     737:             fam_dir->st_dev = st->st_dev;
     738:             fam_dir->st_ino = st->st_ino;
     739:           #ifdef HAVE_SYS_INOTIFY_H
     740:             scf->wds = splaytree_insert_splayed(scf->wds,fam_dir->req,fam_dir);
     741:           #endif
     742:         }
     743:         fam_dir->stat_ts = cur_ts;
     744:     }
     745: 
     746:     if (NULL == fam_dir) {
>>   747:         fam_dir = fam_dir_entry_init(fn, dirlen);
     748: 
>>   749:         if (0 != FAMMonitorDirectory(&scf->fam,fam_dir->name.ptr,&fam_dir->req,
     750:                                      (void *)(intptr_t)dir_ndx)) {
     751:           #if defined(HAVE_SYS_INOTIFY_H) \
     752:            || (defined HAVE_SYS_EVENT_H && defined HAVE_KQUEUE)
     753:             log_perror(scf->errh, __FILE__, __LINE__,
     754:               "monitoring dir failed: %s file: %s",
     755:               fam_dir->name.ptr, fn);
     756:           #else
     757:             log_error(scf->errh, __FILE__, __LINE__,
     758:               "monitoring dir failed: %s file: %s %s",
     759:               fam_dir->name.ptr, fn, FamErrlist[FAMErrno]);
     760:           #endif
     761:             fam_dir_entry_free(fam_dir);
     762:             return NULL;
     763:         }
     764: 
     765:         scf->dirs = splaytree_insert_splayed(scf->dirs, dir_ndx, fam_dir);
     766:       #ifdef HAVE_SYS_INOTIFY_H
     767:         scf->wds = splaytree_insert(scf->wds, fam_dir->req, fam_dir);
     768:       #endif
     769:         fam_dir->stat_ts= cur_ts;
     770:         fam_dir->st_dev = st->st_dev;
     771:         fam_dir->st_ino = st->st_ino;
     772:     }
     773: 
     774:     if (ck_lnk) {
     775:         if (fn_is_dir) {
     776:             /*(temporarily modify fn)*/
     777:             char e = fn[dirlen];
     778:             fn[dirlen] = '\0';
     779:             if (0 != lstat(fn, &lst)) {
     780:                 fn[dirlen] = e;
     781:                 return NULL;
     782:             }
     783:             fn[dirlen] = e;
     784:         }
     785:         if (fam_dir->fam_parent) {
     786:             --fam_dir->fam_parent->refcnt;
     787:             fam_dir->fam_parent = NULL;
     788:         }
     789:         if (S_ISLNK(lst.st_mode)) {
     790:             fam_dir->fam_parent = fam_dir_monitor(scf, fn, dirlen, &lst);
     791:         }
     792:     }
     793: 
     794:     ++fam_dir->refcnt;
     795:     return fam_dir;
     796: }
